package com.harmony.retail.web;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ModelAttribute;

/**
 * 全 Controller 共通の Model 属性を提供する Advice。
 *
 * PageLayout / Gadget で参照される storeName / userName / copyright / version を
 * application.properties から注入する。本来は authentication interceptor / session
 * から取得する想定。
 *
 * Generated by Harmony /generate-code (RFC #1021 pl-7) — Gadget の ModelAttribute 配線。
 */
@ControllerAdvice
public class CommonModelAdvice {

    @Value("${app.session.storeName:店舗未選択}")
    private String storeName;

    @Value("${app.session.userName:ゲスト}")
    private String userName;

    @Value("${app.copyright:© 2026 Harmony Retail Inc.}")
    private String copyright;

    @Value("${app.version:v1.0.0}")
    private String version;

    @ModelAttribute("storeName")
    public String storeName() {
        return storeName;
    }

    @ModelAttribute("userName")
    public String userName() {
        return userName;
    }

    @ModelAttribute("copyright")
    public String copyright() {
        return copyright;
    }

    @ModelAttribute("version")
    public String version() {
        return version;
    }
}
